4951 void computeKnownFPClass(const Value *V, const APInt &DemandedElts,
4952                          FPClassTest InterestedClasses, KnownFPClass &Known,
4953                          const SimplifyQuery &Q, unsigned Depth) {
4954   assert(Known.isUnknown() && "should not be called with known information");
