4992       if (!DemandedElts[i])
4993         continue;
4994 
4995       Constant *Elt = CV->getAggregateElement(i);
4996       if (!Elt) {
4997         Known = KnownFPClass();
4998         return;
4999       }
5000       if (isa<PoisonValue>(Elt))
5001         continue;
5002       auto *CElt = dyn_cast<ConstantFP>(Elt);
5003       if (!CElt) {
5004         Known = KnownFPClass();
5005         return;
5006       }
5007 
5008       const APFloat &C = CElt->getValueAPF();
5009       Known.KnownFPClasses |= C.classify();
5010       if (C.isNegative())
5011         SignBitAllZero = false;
5012       else
5013         SignBitAllOne = false;
5014     }
5015     if (SignBitAllOne != SignBitAllZero)
5016       Known.SignBit = SignBitAllOne;
5017     return;
5018   }
5019 
5020   FPClassTest KnownNotFromFlags = fcNone;
5021   if (const auto *CB = dyn_cast<CallBase>(V))
5022     KnownNotFromFlags |= CB->getRetNoFPClass();
5023   else if (const auto *Arg = dyn_cast<Argument>(V))
5024     KnownNotFromFlags |= Arg->getNoFPClass();
5025 
5026   const Operator *Op = dyn_cast<Operator>(V);
5027   if (const FPMathOperator *FPOp = dyn_cast_or_null<FPMathOperator>(Op)) {
5028     if (FPOp->hasNoNaNs())
5029       KnownNotFromFlags |= fcNan;
5030     if (FPOp->hasNoInfs())
5031       KnownNotFromFlags |= fcInf;
5032   }
