5054   // All recursive calls that increase depth must come after this.
5055   if (Depth == MaxAnalysisRecursionDepth)
5056     return;
5057 
5058   const unsigned Opc = Op->getOpcode();
5059   switch (Opc) {
5060   case Instruction::FNeg: {
5061     computeKnownFPClass(Op->getOperand(0), DemandedElts, InterestedClasses,
5062                         Known, Q, Depth + 1);
5063     Known.fneg();
5064     break;
5065   }
5066   case Instruction::Select: {
5067     auto ComputeForArm = [&](Value *Arm, bool Invert) {
5068       KnownFPClass Res;
5069       computeKnownFPClass(Arm, DemandedElts, InterestedClasses, Res, Q,
5070                           Depth + 1);
