5072                                      Depth);
5073       return Res;
5074     };
5075     // Only known if known in both the LHS and RHS.
5076     Known =
5077         ComputeForArm(Op->getOperand(1), /*Invert=*/false)
5078             .intersectWith(ComputeForArm(Op->getOperand(2), /*Invert=*/true));
5079     break;
5080   }
