4791       (CondIsTrue ? match(Cond, m_LogicalAnd(m_Value(A), m_Value(B)))
4792                   : match(Cond, m_LogicalOr(m_Value(A), m_Value(B))))) {
4793     computeKnownFPClassFromCond(V, A, CondIsTrue, CxtI, KnownFromContext,
4794                                 Depth + 1);
