4798   }
4799   if (Depth < MaxAnalysisRecursionDepth && match(Cond, m_Not(m_Value(A)))) {
4800     computeKnownFPClassFromCond(V, A, !CondIsTrue, CxtI, KnownFromContext,
4801                                 Depth + 1);
